// Search queries that target German Shopify stores.
// Varying the phrasing increases the number of unique domains found.
const queries = [
  '"powered by shopify" site:.de',
  '"powered by shopify" impressum site:.de',
  'shopify online shop deutschland impressum site:.de',
  'shopify shop site:.de -myshopify.com'
];

return queries.map((query, idx) => ({ json: { query, idx } }));

const response = $input.item.json;

// Domains that are platforms or directories, not individual stores
const SKIP_DOMAINS = [
  'myshopify.com', 'shopify.com', 'reddit.com', 'youtube.com', 'wikipedia.org',
  'twitter.com', 'facebook.com', 'instagram.com', 'linkedin.com', 'xing.com',
  'google.com', 'amazon.de', 'ebay.de', 'otto.de', 'zalando.de',
  'shopify-brands.de', 'shopify-agentur', 'ionos.de', 'strikingly.com',
  'trustpilot.com', 'yelp.de', 'tripadvisor.de', 'gmbh-verzeichnis.de'
];

const items = [];
const seen = new Set();

for (const result of (response.organic_results || [])) {
  if (!result.link) continue;
  try {
    const u = new URL(result.link);
    const domain = u.hostname.replace(/^www\./, '');
    if (!domain.endsWith('.de')) continue;
    if (SKIP_DOMAINS.some(s => domain.includes(s))) continue;
    if (seen.has(domain)) continue;
    seen.add(domain);
    items.push({
      json: {
        company_name: result.title || domain,
        domain,
        url: `https://${domain}`,
        description: result.snippet || '',
        search_query: response.search_parameters?.q || ''
      }
    });
  } catch (_) {}
}

return items.length ? items : [{ json: { _skip: true } }];

const all = $input.item.json.leads || [];
const seen = new Set();
const unique = [];
const today = new Date().toISOString().split('T')[0];

for (const lead of all) {
  if (lead._skip || !lead.domain) continue;
  if (seen.has(lead.domain)) continue;
  seen.add(lead.domain);
  unique.push({ ...lead, date_found: today });
}

console.log(`${unique.length} unique leads found`);
return unique.map(l => ({ json: l }));
